def factorial(n):
    # Base case: factorial of 0 or 1 is 1
    if n == 0 or n == 1:
        return 1
    # Recursive case: multiply n by factorial of n - 1
    return n * factorial(n - 1)

def second_largest(nums):
    """Return the second largest distinct integer in the list."""
    if len(nums) < 2:
        raise ValueError("List must contain at least two elements")

    first = float('-inf')
    second = float('-inf')

    for n in nums:
        if n > first:
            second = first
            first = n
        elif first > n > second:
            second = n

    if second == float('-inf'):
        raise ValueError("No distinct second largest value found")

    return second
